format:
{% if active %}<active/>{% endif %}{% if is_claude is defined and not is_claude %}{% if '/' in app_icon %}<icon watermark='1' src='{{ app_icon }}'/>{% else %}<icon watermark='1' name='{{ app_icon | default('app') }}'/>{% endif %}<span size='x-large' weight='bold' foreground='#cdd6f4'>{{ shortcut }}</span><sep/><span weight='bold' foreground='#89b4fa'>{{ app }}</span>
<wrap><span size='small' foreground='#a6adc8'>{{ title }}</span></wrap>{% else %}{% set prompting = sessions[0].state == 'prompt' or ((sessions | length) > 1 and sessions[1].state == 'prompt') %}{% if prompting %}<pulse>{% endif %}{% if (sessions | length) > 1 %}<gutter><span size='200%' weight='bold' foreground='#cdd6f4'>{{ shortcut }}</span></gutter>{% for s in sessions %}<status state='{{ s.state }}' level='{{ s.idle_level | default(0) }}' ago='{{ s.idle_ago | default('') }}'/> <span weight='bold' foreground='#89b4fa'>{{ s.folder }}</span>{% if s.unpushed and s.state != 'idle' %} <span weight='bold' foreground='#a6e3a1'>↑{{ s.unpushed }}</span>{% endif %}
<tickerbox width='180'><span size='small' foreground='#a6adc8'>{{ s.title | default('') }}</span></tickerbox>{% if not loop.last %}
{% endif %}{% endfor %}{% else %}{% set s = sessions[0] %}<span size='x-large' weight='bold' foreground='#cdd6f4'>{{ shortcut }}</span> <status state='{{ s.state }}' level='{{ s.idle_level | default(0) }}' ago='{{ s.idle_ago | default('') }}'/> <span weight='bold' foreground='#89b4fa'>{{ s.folder }}</span>{% if s.unpushed and s.state != 'idle' %} <span weight='bold' foreground='#a6e3a1'>↑{{ s.unpushed }}</span>{% endif %}
<wrap><span size='small' foreground='#a6adc8'>{{ s.title | default('') }}</span></wrap>{% endif %}{% if prompting %}</pulse>{% endif %}{% endif %}
